<template><div class="page"><div class="head"><h1>教学资源审核</h1><el-button @click="load">刷新</el-button></div><el-table :data="items" v-loading="loading"><el-table-column prop="courseName" label="课程"/><el-table-column prop="chapterName" label="章节"/><el-table-column prop="teacherName" label="教师" width="100"/><el-table-column prop="title" label="资源名称"/><el-table-column label="类型" width="90"><template #default="{row}">{{row.kind==='video'?'视频':'PDF'}}</template></el-table-column><el-table-column label="预览" width="90"><template #default="{row}"><el-button link type="primary" @click="preview(row)">预览</el-button></template></el-table-column><el-table-column label="操作" width="180"><template #default="{row}"><el-button type="success" size="small" @click="review(row,true)">通过</el-button><el-button type="danger" size="small" @click="review(row,false)">拒绝</el-button></template></el-table-column></el-table><el-empty v-if="!loading&&!items.length" description="暂无待审核资源"/></div></template>
<script setup>import {onMounted,ref} from 'vue';import {ElMessage,ElMessageBox} from 'element-plus';import {getPendingResources,reviewResource} from '../../api/courseContent.js';const items=ref([]),loading=ref(false);async function load(){loading.value=true;try{items.value=await getPendingResources()}finally{loading.value=false}}function preview(r){window.open(r.url,'_blank')}async function review(r,approved){let comment='审核通过';if(!approved){const x=await ElMessageBox.prompt('请输入拒绝原因','资源审核',{inputValidator:v=>!!v?.trim()||'请输入原因'});comment=x.value}await reviewResource(r.kind,r.id,{approved,comment});ElMessage.success('审核完成');await load()}onMounted(load)</script><style scoped>.page{background:#fff;padding:24px;border-radius:16px}.head{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px}</style>
